const { BigQuery } = require('@google-cloud/bigquery');

/**
 * Cloud Function to aggregate data from BigQuery.
 * This function is designed to be deployed with high memory (8GB) and timeout (540s)
 * to handle large data processing tasks.
 *
 * @param {object} req The HTTP request payload.
 * @param {object} res The HTTP response object.
 */
exports.processBigData = async (req, res) => {
  const bigquery = new BigQuery();

  // IMPORTANT: Replace with your actual BigQuery project, dataset, and table IDs.
  // The GCP_PROJECT environment variable is automatically set in Cloud Functions.
  const projectId = process.env.GCP_PROJECT || 'your-gcp-project-id';
  const datasetId = 'your_dataset_id';
  const tableId = 'your_table_id';

  // Define your BigQuery SQL query for aggregation.
  // This is an example query. Customize it to fit your data and aggregation needs.
  // Ensure your query is optimized for performance on large datasets.
  const query = `
    SELECT
      category_column,
      COUNT(*) AS record_count,
      SUM(value_column) AS total_value,
      AVG(another_value_column) AS average_value
    FROM
      \`${projectId}.${datasetId}.${tableId}\`
    WHERE
      timestamp_column >= TIMESTAMP_SUB(CURRENT_TIMESTAMP(), INTERVAL 30 DAY)
    GROUP BY
      category_column
    ORDER BY
      record_count DESC
    LIMIT 10000; -- Adjust limit based on expected output size
  `;

  const options = {
    query: query,
    // Specify the BigQuery dataset location (e.g., 'US', 'EU', 'asia-northeast1').
    // This should match the location of your dataset.
    location: 'US',
    // For very large result sets that exceed Cloud Function memory limits
    // or HTTP response size limits, consider writing results to a destination table
    // or Google Cloud Storage instead of fetching them directly.
    // destinationTable: {
    //   projectId: projectId,
    //   datasetId: 'your_results_dataset',
    //   tableId: 'your_results_table',
    // },
    // writeDisposition: 'WRITE_TRUNCATE', // Overwrite table if it exists
  };

  try {
    console.log('Starting BigQuery aggregation job...');
    console.log('Query:', query);

    // Run the query as a job. This is suitable for long-running queries.
    const [job] = await bigquery.createQueryJob(options);
    console.log(`BigQuery Job ${job.id} started.`);

    // Wait for the query job to complete and get the results.
    // For extremely large results, this might still consume significant memory.
    // Consider streaming results or writing to a destination table/GCS.
    const [rows] = await job.getQueryResults();

    console.log(`BigQuery Job ${job.id} completed. Fetched ${rows.length} rows.`);

    // Respond with a summary or a subset of the results.
    // Avoid returning extremely large datasets directly via HTTP response.
    res.status(200).send({
      message: 'BigQuery aggregation completed successfully.',
      jobId: job.id,
      rowCount: rows.length,
      // Example: Return first 10 rows as a sample
      sampleResults: rows.slice(0, 10),
      // If results were written to a destination table, you might return its ID.
      // destinationTableId: options.destinationTable ? `${options.destinationTable.datasetId}.${options.destinationTable.tableId}` : undefined,
    });

  } catch (error) {
    console.error('ERROR during BigQuery aggregation:', error);
    res.status(500).send({
      message: 'Error processing BigQuery data.',
      error: error.message,
      details: error.errors ? error.errors.map(e => e.message) : undefined,
    });
  }
};

